102→private fun Job.setupCancellation(future: CompletableFuture<*>) {
103→    future.handle { _, exception ->
104→        cancel(exception?.let {
105→            it as? CancellationException ?: CancellationException("CompletableFuture was completed exceptionally", it)
106→        })
