110→/**
111→ * Converts this [CompletionStage] to an instance of [Deferred].
112→ *
113→ * The [CompletableFuture] that corresponds to this [CompletionStage] (see [CompletionStage.toCompletableFuture])
114→ * is cancelled when the resulting deferred is cancelled.
115→ */
116→@Suppress("DeferredIsResult")
117→public fun <T> CompletionStage<T>.asDeferred(): Deferred<T> {
118→    val future = toCompletableFuture() // retrieve the future
119→    // Fast path if already completed
120→    if (future.isDone) {
121→        return try {
122→            @Suppress("UNCHECKED_CAST")
123→            CompletableDeferred(future.get() as T)
124→        } catch (e: Throwable) {
125→            // unwrap original cause from ExecutionException
126→            val original = (e as? ExecutionException)?.cause ?: e
127→            CompletableDeferred<T>().also { it.completeExceptionally(original) }
128→        }
129→    }
130→    val result = CompletableDeferred<T>()
131→    handle { value, exception ->
132→        try {
133→            if (exception == null) {
134→                // the future has completed normally
135→                result.complete(value)
136→            } else {
137→                // the future has completed with an exception, unwrap it consistently with fast path
138→                // Note: In the fast-path the implementation of CompletableFuture.get() does unwrapping
139→                result.completeExceptionally((exception as? CompletionException)?.cause ?: exception)
140→            }
141→        } catch (e: Throwable) {
142→            // We come here iff the internals of Deferred threw an exception during its completion
143→            handleCoroutineException(EmptyCoroutineContext, e)
144→        }
145→    }
146→    result.cancelFutureOnCompletion(future)
147→    return result
148→}
