150→/**
151→ * Awaits for completion of [CompletionStage] without blocking a thread.
152→ *
153→ * This suspending function is cancellable.
154→ * If the [Job] of the current coroutine is cancelled or completed while this suspending function is waiting, this function
155→ * stops waiting for the completion stage and immediately resumes with [CancellationException][kotlinx.coroutines.CancellationException].
156→ *
157→ * This method is intended to be used with one-shot futures, so on coroutine cancellation the [CompletableFuture] that
158→ * corresponds to this [CompletionStage] (see [CompletionStage.toCompletableFuture])
159→ * is cancelled. If cancelling the given stage is undesired, `stage.asDeferred().await()` should be used instead.
160→ */
161→public suspend fun <T> CompletionStage<T>.await(): T {
162→    val future = toCompletableFuture() // retrieve the future
163→    // fast path when CompletableFuture is already done (does not suspend)
164→    if (future.isDone) {
165→        try {
166→            @Suppress("UNCHECKED_CAST", "BlockingMethodInNonBlockingContext")
167→            return future.get() as T
168→        } catch (e: ExecutionException) {
169→            throw e.cause ?: e // unwrap original cause from ExecutionException
170→        }
171→    }
172→    // slow path -- suspend
173→    return suspendCancellableCoroutine { cont: CancellableContinuation<T> ->
174→        val consumer = ContinuationHandler(cont)
175→        handle(consumer)
176→        cont.invokeOnCancellation {
177→            future.cancel(false)
178→            consumer.cont = null // shall clear reference to continuation to aid GC
179→        }
180→    }
181→}
182→
183→private class ContinuationHandler<T>(
184→    @Volatile @JvmField var cont: Continuation<T>?
185→) : BiFunction<T?, Throwable?, Unit> {
186→    @Suppress("UNCHECKED_CAST")
187→    override fun apply(result: T?, exception: Throwable?) {
188→        val cont = this.cont ?: return // atomically read current value unless null
189→        if (exception == null) {
190→            // the future has completed normally
191→            cont.resume(result as T)
192→        } else {
193→            // the future has completed with an exception, unwrap it to provide consistent view of .await() result and to propagate only original exception
194→            cont.resumeWithException((exception as? CompletionException)?.cause ?: exception)
195→        }
196→    }
197→}
