 75→public fun <T> Deferred<T>.asCompletableFuture(): CompletableFuture<T> {
 76→    val future = CompletableFuture<T>()
 77→    setupCancellation(future)
 78→    invokeOnCompletion {
 79→        try {
 80→            future.complete(getCompleted())
 81→        } catch (t: Throwable) {
 82→            future.completeExceptionally(t)
 83→        }
 84→    }
 85→    return future
